import type { AudioEffect } from "./BaseEffect.js";
import { compressSample } from "./utils.js";

export class CompressorEffect implements AudioEffect {
  readonly name = "compressor";
  private _enabled: boolean;

  constructor(enabled: boolean) {
    this._enabled = enabled;
  }

  get enabled(): boolean {
    return this._enabled;
  }

  setEnabled(v: boolean): void {
    this._enabled = v;
  }

  isActive(): boolean {
    return this._enabled;
  }

  process(samples: Float64Array, _channels: number, _frames: number): void {
    if (!this._enabled) return;
    for (let i = 0; i < samples.length; i++) {
      samples[i] = compressSample(samples[i]!);
    }
  }

  reset(): void {
    // no state
  }
}
